import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreEmptyLines() {
        CSVFormat original = CSVFormat.DEFAULT;
        assertFalse(original.getIgnoreEmptyLines());

        CSVFormat updated = original.withIgnoreEmptyLines();
        assertNotNull(updated);
        assertTrue(updated.getIgnoreEmptyLines());

        // Ensure original remains unchanged (immutability)
        assertFalse(original.getIgnoreEmptyLines());

        // Calling withIgnoreEmptyLines() on updated again returns same or equivalent with true
        CSVFormat updatedAgain = updated.withIgnoreEmptyLines();
        assertTrue(updatedAgain.getIgnoreEmptyLines());

        // equals and hashCode consistency for updated formats
        assertEquals(updated.hashCode(), updatedAgain.hashCode());
        assertEquals(updated, updatedAgain);
    }
}
